package com.backend.suits.authentication.controllers;import com.backend.suits.authentication.model.LoginRequest;import com.backend.suits.authentication.model.LoginResponse;import com.backend.suits.authentication.model.RegisterRequest;import com.backend.suits.authentication.model.RegisterResponse;import com.backend.suits.entity.Role;import com.backend.suits.entity.User;import com.backend.suits.repository.UserRepository;import com.backend.suits.service.JwtUtil;import com.backend.suits.service.UserService;import jakarta.servlet.http.HttpServletResponse;import org.springframework.http.HttpHeaders;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseCookie;import org.springframework.http.ResponseEntity;import org.springframework.security.authentication.AuthenticationManager;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.Authentication;import org.springframework.security.core.AuthenticationException;import org.springframework.security.core.context.SecurityContextHolder;import org.springframework.web.bind.annotation.*;import org.springframework.web.server.ResponseStatusException;import java.time.Duration;@RestControllerpublic class  AuthController {    public static final String LOGIN = "/login";    public static final String REGISTER_PROFESSIONAL = "/register/professional";    public static final String REGISTER_CLIENT = "/register/client";    private final AuthenticationManager authenticationManager;    private final JwtUtil jwtUtil;    private final UserService userService;    private final UserRepository userRepository;    public AuthController(AuthenticationManager authenticationManager, JwtUtil jwtUtil, UserService userService, UserRepository userRepository){        this.authenticationManager = authenticationManager;        this.jwtUtil = jwtUtil;        this.userService = userService;        this.userRepository = userRepository;    }    @PostMapping(LOGIN)    public ResponseEntity<LoginResponse> login(@RequestBody LoginRequest loginRequest, HttpServletResponse response) {        try {                if (loginDataFormatIsInvalid(loginRequest)) {                    return ResponseEntity.badRequest().body(null);                }                Authentication authentication = authenticationManager.authenticate(                        new UsernamePasswordAuthenticationToken(loginRequest.username(), loginRequest.password()));                SecurityContextHolder.getContext().setAuthentication(authentication);                User user = userService.findByUsername(loginRequest.username()).orElseThrow();                String token = jwtUtil.generateToken(user);                ResponseCookie userSessionCookie = ResponseCookie.from("SUITS_Token", token)                        .secure(true)                        .httpOnly(true)                        .path("/")                        .maxAge(Duration.ofHours(1))                        .sameSite("None")                        .build();                response.addHeader(HttpHeaders.SET_COOKIE, userSessionCookie.toString());                LoginResponse responseBody = new LoginResponse(user.getUsername(), user.getRole().toString());                return ResponseEntity.ok().body(responseBody);        }catch (AuthenticationException e){            throw new ResponseStatusException(HttpStatus.FORBIDDEN, e.getMessage());        }catch (ResponseStatusException e) {            throw e;        } catch (Exception e) {            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR,                    "Erreur innatendue lors de l'ouverture de la session.");        }    }    @PostMapping("login/register")    public ResponseEntity<?> register(@RequestBody RegisterRequest request) {        try{            if (registerDataFormatIsInvalid(request)) {                return ResponseEntity.badRequest().body(null);            }            if (userRepository.findByUsername(request.username()).isPresent()) {                return ResponseEntity.badRequest().body("Ce courriel est déjà utilisé!");            }            Role newUserRole = Role.valueOf("CLIENT");            User newUser = new User(request.username(), request.password(), request.name(), newUserRole);            User savedUser = userService.register(newUser);            RegisterResponse registerResponse = new RegisterResponse(savedUser.getUsername(), savedUser.getName(), savedUser.getRole());            return ResponseEntity.ok(registerResponse);        }catch (ResponseStatusException e) {            throw e;        } catch (Exception e) {            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR,                "Erreur innatendue lors de l'ouverture de la session.");        }    }    private boolean loginDataFormatIsInvalid(LoginRequest loginRequest) {        String emailRegex = "[A-Za-z0-9._%+\\-]+@[A-Za-z0-9.\\-]+\\.[A-Za-z]{2,}";        String passwordRegex = "^(?=.*?[A-Z])(?=.*?[a-z])(?=.*?[0-9])(?=.*?[^A-Za-z0-9]).{12,}$";        return loginRequest.username() == null                || loginRequest.username().isBlank()                || loginRequest.username().contains(" ")                || !loginRequest.username().matches(emailRegex)                || loginRequest.password() == null                || loginRequest.password().isBlank()                || loginRequest.password().contains(" ")                || !loginRequest.password().matches(passwordRegex);    }    private boolean registerDataFormatIsInvalid(RegisterRequest request) {        String emailRegex = "[A-Za-z0-9._%+\\-]+@[A-Za-z0-9.\\-]+\\.[A-Za-z]{2,}";        String passwordRegex = "^(?=.*?[A-Z])(?=.*?[a-z])(?=.*?[0-9])(?=.*?[^A-Za-z0-9]).{12,}$";        return request.username() == null                || request.username().isBlank()                || request.username().contains(" ")                || !request.username().matches(emailRegex)                || request.password() == null                || request.password().isBlank()                || request.password().contains(" ")                || !request.password().matches(passwordRegex)                || request.name() == null                || request.name().isBlank();    }    @GetMapping("client")    public ResponseEntity<?> getClient() {        return ResponseEntity.ok("Nous affichons un client !");    }    @GetMapping("professionnel")    public ResponseEntity<?> getProf() {        return ResponseEntity.ok("Nous affichons un professionnel !");    }    @PutMapping(REGISTER_PROFESSIONAL)    public ResponseEntity<?> registerProfessional(@RequestBody RegisterRequest request) {        try{            if (registerDataFormatIsInvalid(request)) {                return ResponseEntity.badRequest().body(null);            }            if (userRepository.findByUsername(request.username()).isPresent()) {                return ResponseEntity.badRequest().body("Ce courriel est déjà utilisé!");            }            Role newUserRole = Role.valueOf("PROFESSIONNEL");            User newUser = new User(request.username(), request.password(), request.name(), newUserRole);            User savedUser = userService.register(newUser);            RegisterResponse registerResponse = new RegisterResponse(savedUser.getUsername(), savedUser.getName(), savedUser.getRole());            return ResponseEntity.ok(registerResponse);        }catch (ResponseStatusException e) {            throw e;        } catch (Exception e) {            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR,                   e.getMessage());        }    }    @PutMapping(REGISTER_CLIENT)    public ResponseEntity<?> registerClient(@RequestBody RegisterRequest request) {        try{            if (registerDataFormatIsInvalid(request)) {                return ResponseEntity.badRequest().body(null);            }            if (userRepository.findByUsername(request.username()).isPresent()) {                return ResponseEntity.badRequest().body("Ce courriel est déjà utilisé!");            }            Role newUserRole = Role.valueOf("CLIENT");            User newUser = new User(request.username(), request.password(), request.name(), newUserRole);            User savedUser = userService.register(newUser);            RegisterResponse registerResponse = new RegisterResponse(savedUser.getUsername(), savedUser.getName(), savedUser.getRole());            return ResponseEntity.ok(registerResponse);        }catch (ResponseStatusException e) {            throw e;        } catch (Exception e) {            throw new ResponseStatusException(HttpStatus.INTERNAL_SERVER_ERROR,                    "Erreur innatendue lors de l'ouverture de la session.");        }    }}